{"npsn":"103121","name":"STIKES Prima Nusantara","address":"Jl.KUSUMA BHAKTI No 99 GULAI BANCAH","village":"Pulai Anak Air","status":"Swasta","jenjang":"UNIVERSITAS","district":"Mandiangin Koto Selayan","regencyBpsCode":"1375","regencyName":"Kota Bukittinggi","provinceName":"Sumatera Barat","school_id":"ec3f8049-b0c9-40b1-84b7-1ec579bf1f46","user_id":"9b51f822-1a6c-46c4-bae0-7d2944f15f9f","password_hash":"$2b$04$pOqVCENvXdEE.Oj/pOWlKutHiLopXV/mHxAkhWtaFDDlp16RXGxGW"},
{"npsn":"101032","name":"Universitas Fort De Kock","address":"Jl. Soekarno Hatta No.11, Manggis Ganting","village":"Koto Selayan","status":"Swasta","jenjang":"UNIVERSITAS","district":"Mandiangin Koto Selayan","regencyBpsCode":"1375","regencyName":"Kota Bukittinggi","provinceName":"Sumatera Barat","school_id":"f775bad0-65f2-4414-bf9c-92d16087a6bb","user_id":"e56b076e-884d-4c35-85b8-518c71420a41","password_hash":"$2b$04$pOqVCENvXdEE.Oj/pOWlKuXrTqJX/u56hTEOwKzdKR6snLOuOQLAO"},
{"npsn":"103002","name":"STKIP Ahlussunnah","address":"Jl. Diponegoro No. 8","village":"Kec. Aur Birugo Tigo Baleh","status":"Swasta","jenjang":"UNIVERSITAS","district":"Aur Birugo Tigo Baleh","regencyBpsCode":"1375","regencyName":"Kota Bukittinggi","provinceName":"Sumatera Barat","school_id":"e2220ec3-fb71-4cb0-a79f-3733a45dc221","user_id":"7c565eaf-311b-459a-94ce-24bb0f5cf87e","password_hash":"$2b$04$pOqVCENvXdEE.Oj/pOWlKuCpkb0RxRocI1wZnTeZfAf9VVHP7JfoK"}
]'::json;
BEGIN
    PERFORM set_config('statement_timeout', '120000', true);

    -- 1. Insert schools
    INSERT INTO public.schools (id, name, npsn, location, accreditation, regency_id)
    SELECT 
        (x.school_id)::uuid, 
        x.name, 
        x.npsn, 
        concat_ws(', ', nullif(x.address, ''), nullif(x.village, ''), nullif(x.district, ''), nullif(x."regencyName", ''), x."provinceName"),
        'C',
        r.id
    FROM json_to_recordset(v_data) AS x(
        school_id text, name text, npsn text, address text, village text, district text, "regencyName" text, "regencyBpsCode" text, "provinceName" text
    )
    JOIN public.regencies r ON r.code = x."regencyBpsCode"
    WHERE NOT EXISTS (SELECT 1 FROM public.schools s WHERE s.npsn = x.npsn);

    -- 2. Insert auth.users
    INSERT INTO auth.users (
        instance_id, id, aud, role, email, encrypted_password, 
        email_confirmed_at, recovery_sent_at, last_sign_in_at, 
        raw_app_meta_data, raw_user_meta_data, created_at, updated_at, 
        confirmation_token, email_change, email_change_token_new, recovery_token
    )
    SELECT 
        '00000000-0000-0000-0000-000000000000'::uuid, 
        (x.user_id)::uuid, 
        'authenticated', 
        'authenticated', 
        x.npsn || '@mail.com', 
        x.password_hash, 
        now(), now(), now(), 
        json_build_object('provider', 'email', 'providers', json_build_array('email'))::jsonb, 
        '{}'::jsonb, 
        now(), now(), '', '', '', ''
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text, password_hash text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.users u WHERE u.email = x.npsn || '@mail.com');

    -- 3. Insert auth.identities
    INSERT INTO auth.identities (
        id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
    )
    SELECT 
        (x.user_id)::uuid, 
        (x.user_id)::uuid, 
        x.user_id, 
        json_build_object('sub', x.user_id, 'email', x.npsn || '@mail.com')::jsonb, 
        'email', 
        now(), now(), now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.identities i WHERE i.id = (x.user_id)::uuid);

    -- 4. Insert public.profiles
    INSERT INTO public.profiles (id, role, school_id, created_at)
    SELECT 
        (x.user_id)::uuid, 
        'SCHOOL', 
        (x.school_id)::uuid, 
        now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, school_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = (x.user_id)::uuid);
END $$;
